<A>[遍历记录池开始][upbs_datasync][enable_status = '1'][table_name = @table_name, dataload_type = @dataload_type, dataload_str = @dataload_str, data_source = @data_source, sql_str = @sql_str]
{
  //竞价表数据加载
  if (@dataload_str[0] == '1')
  {
    //20250915 wangyq mod 支持按照表中配置sql加载数据 修改单：T202509133306
    // 配置sql模式
    if (0 != hs_isnull_s(@sql_str))
    {
      [AF_数据准备公用_SQL转换][partition_no=@partition_no, ldp_short_appname=@ldp_short_appname][sql_str=@sql_str]
    }
    // 原硬编码模式
    else
    {
      if (@dataload_type == '1')
      {
        if (hs_strcmp(@table_name, "uses_fund_account") == 0)
        {
          sprintf(@sql_str, "select a.* from uses_fund_account a where a.partition_no = %d", @partition_no);
        }
        else if (hs_strcmp(@table_name, "client_prefer") == 0)
        {
          sprintf(@sql_str, "select a.* from %s a where exists(select 1 from uses_fund_account b where b.client_id = a.client_id and b.partition_no = %d)", @table_name, @partition_no);
        }
        else if (hs_strcmp(@table_name, "uses_serial_counter") == 0)
        {
          // 支持uses_serial_counter表按分片上场, 支持partition_no=0的基础数据上场
          sprintf(@sql_str, "select a.* from %s a where a.partition_no = %d or a.partition_no = 0", @table_name, @partition_no);
        }
        else if (0 == hs_strcmp(@table_name, "stb_stdholder") || 0 == hs_strcmp(@table_name, "stb_resstock"))
        {
          // 支持关联uses_stock_holder和uses_fund_account表按分片上场 
          sprintf(@sql_str, "select a.* from %s a where exists (select 1 from uses_stock_holder b, uses_fund_account c where a.stock_account = b.stock_account and b.fund_account = c.fund_account and c.partition_no = %d)", @table_name, @partition_no);
        }
        else if (hs_strcmp(@table_name, "uact_client") == 0)
        {
          //20240809 wangjh mod 支持uact_client按分片加载 修改单：T202408093630
          sprintf(@sql_str, "select a.* from %s a where exists(select 1 from uses_fund_account b where b.client_id = a.client_id  and b.partition_no = %d)", @table_name, @partition_no);
        }
        else
        {
          sprintf(@sql_str, "select a.* from %s a,uses_fund_account b where a.fund_account = b.fund_account and b.partition_no = %d", @table_name, @partition_no);
        }
      }
      else if (@dataload_type == '2')
      {
        //TODO：大表分段
        sprintf(@sql_str, "select * from %s ", @table_name);
      }
      else if (@dataload_type == '3')
      {
        //20231124 wangjie mod 序列回库改造
        if (hs_strcmp(@table_name, "upbs_sequence") == 0)
        {
          sprintf(@sql_str, "select a.* from upbs_sequence a where a.ldp_short_appname = '%s'", @ldp_short_appname);
        }
        else
        {
          sprintf(@sql_str, "select a.* from %s a where a.ldp_short_appname = '%s'", @table_name, @ldp_short_appname);
        }
      }
      else
      {
        sprintf(@sql_str, "select * from %s ", @table_name);
      }
    }

    [组件大小][comp_dataload][@count]
    [插入组件][comp_dataload][@count][data_source = @data_source, table_name = @table_name, sql_str = @sql_str]

    //[手工打包体][@table_name, @data_source, @sql_str][@packer]
    if (@dataload_type == '1')
    {
      [手工打包体][@table_name,@data_source,@sql_str,960605,"fund_account","资产账号"][@packer]
    }
    else
    {
      [手工打包体][@table_name,@data_source,@sql_str,960605,"",""][@packer]
    }       
  }
}
